import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { PurchaseOrder, Supplier } from '../../core/models';

/**
 * Purchase orders list. New PO opened via `?modal=new` (pick a supplier; lines
 * added on the detail page). Mutations gated to purchasing + admin.
 */
@Component({
  selector: 'app-purchase-orders',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './purchase-orders.component.html',
  styleUrl: './purchase-orders.component.css',
})
export class PurchaseOrdersComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly saving = signal(false);

  readonly suppliers = signal<Supplier[]>([
    { id: 's1', name: 'Globex Supply Co', email: 'sales@globex.example' },
    { id: 's2', name: 'Initech Components', email: 'orders@initech.example' },
  ]);

  readonly orders = signal<PurchaseOrder[]>([
    { id: 'po1', supplierId: 's1', status: 'draft', createdAt: '2026-07-08T10:00:00Z',
      supplier: { id: 's1', name: 'Globex Supply Co', email: 'sales@globex.example' }, totalCents: 90000 },
    { id: 'po2', supplierId: 's2', status: 'ordered', createdAt: '2026-07-05T09:00:00Z',
      supplier: { id: 's2', name: 'Initech Components', email: 'orders@initech.example' }, totalCents: 48000 },
    { id: 'po3', supplierId: 's1', status: 'received', createdAt: '2026-06-30T14:00:00Z',
      supplier: { id: 's1', name: 'Globex Supply Co', email: 'sales@globex.example' }, totalCents: 128000 },
  ]);

  readonly canEdit = computed(() => this.auth.isPurchasing());

  readonly modalOpen = signal(false);
  form = { supplierId: '' };

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.queryParams.subscribe((q) => {
      this.modalOpen.set(q['modal'] === 'new' && this.canEdit());
      if (this.modalOpen()) this.form = { supplierId: this.suppliers()[0]?.id ?? '' };
    });
  }

  money(cents: number | undefined): string {
    return ((cents ?? 0) / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }

  statusClass(s: string): string {
    return s === 'received' ? 'badge-ok' : s === 'ordered' ? 'badge-info' : 'badge-muted';
  }

  close(): void {
    this.router.navigate([], { queryParams: {} });
    this.modalOpen.set(false);
  }

  create(): void {
    if (!this.form.supplierId) {
      this.error.set('Choose a supplier.');
      return;
    }
    this.saving.set(true);
    const sup = this.suppliers().find((s) => s.id === this.form.supplierId) ?? null;
    const id = 'po' + (this.orders().length + 1);
    this.orders.update((list) => [
      { id, supplierId: this.form.supplierId, status: 'draft', supplier: sup, totalCents: 0, createdAt: '2026-07-12T00:00:00Z' },
      ...list,
    ]);
    this.saving.set(false);
    this.modalOpen.set(false);
    // service_agent: after createPurchaseOrder(), navigate to the detail page.
    this.router.navigate(['/purchase-orders', id]);
  }
}
